const makeTextObsUpdates = (sd, fd, observationCode, testName, valueField = "See report", report, template = {}, conditional = true // Observation should exist only if true
) => {
  const active = fd.field.data;
  const oldObs = sd.webform?.observations?.find(o => o.observationCode === observationCode);
  const oldObsId = oldObs?.observationId ?? 0;
  if (conditional) {
    // There should be an observation

    const newDco = {
      observationId: oldObsId,
      collectedDate: active.dateCreated,
      collectedBy: active.createdBy ?? sd.userProfile?.identity?.fullName,
      orderedBy: active.createdBy ?? sd.userProfile?.identity?.fullName,
      observationCode,
      observationClass: "DCOBS",
      value: valueField,
      units: "",
      valueType: "TEXT",
      status: oldObsId ? "C" : "F",
      description: testName,
      report: report,
      ...template
    };
    return [newDco];
  } else if (oldObsId) {
    // Existing observation, but conditional is now false
    return [{
      observationId: -oldObsId
    }]; // Delete obsolete value
  }
};

